/**
 * Function: Test batch execution reduces recomputation count
 *
 * @param initialA Initial value for variable a
 * @param initialB Initial value for variable b
 * @param nonBatchA Value to set a without batching
 * @param nonBatchB Value to set b without batching
 * @param batchA Value to set a within batch
 * @param batchB Value to set b within batch
 * @return std::tuple<int, int, int> {final sum, count after non-batch updates, count after batch updates}
 */
std::tuple<int, int, int> test_batch_execution(int initialA,
                                               int initialB,
                                               int nonBatchA,
                                               int nonBatchB,
                                               int batchA,
                                               int batchB) {
    // 1. Create reactive variables for a and b
    auto a = reaction::var(initialA);
    auto b = reaction::var(initialB);

    // 2. Create counter variable to track recomputation count
    auto counter = reaction::var(0);

    // 3. Create calculation that sums a and b and increments counter
    auto sum_calc = reaction::calc([&]() {
        // Increment counter each time this calculation is recomputed
        counter.value(counter.get() + 1);
        return a.get() + b.get();
    });

    // 4. Update a and b with non-batch values
    a.value(nonBatchA);
    b.value(nonBatchB);

    // 5. Get current counter value after non-batch updates
    int countAfterNonBatch = counter.get();

    // 6. Create batch context
    auto batch_update = reaction::batch([&]() {
        // 7. Update a and b with batch values inside batch context
        a.value(batchA);
        b.value(batchB);
    });

    // 8. Execute the batch
    batch_update.execute();

    // 9. Get final counter value after batch updates
    int countAfterBatch = counter.get();

    // 10. Return tuple with final sum, count after non-batch, and count after batch
    return std::make_tuple(sum_calc.get(), countAfterNonBatch, countAfterBatch);
}

}  // namespace test_reaction
```

