    auto statusCalc = calc([&]() -> std::string {
        // This calculation will only trigger when the filter condition is met
        double currentValue = sensor();
        double delta = std::abs(currentValue - lastValue());

        // Update lastValue for next comparison
        lastValue.value(currentValue);

        // Increment recompute count
        recomputeCount.value(recomputeCount() + 1);

        // Determine status based on levelThreshold
        return currentValue > levelThreshold ? "HIGH" : "NORMAL";
    });

    // 4. Apply filter to the calculation
    statusCalc.filter([&]() -> bool {
        double current = sensor();
        double last = lastValue();
        return std::abs(current - last) > diffThreshold;
