#pragma once

#include <cstddef>
#include <reaction/memory/memory_config.h>

namespace test_reaction {

struct TinyPod {
    int a;
    int b;
};

struct MediumPod {
    double values[3];  // 24 bytes
};

struct LargePod {
    std::byte payload[128];
};

struct SboTraitSummary {
    bool tinyAlwaysSbo;
    bool tinyForceHeap;
    bool mediumConditionalSbo;
    bool mediumForceHeap;
    bool largeForceHeap;
    std::size_t alwaysThreshold;
    std::size_t conditionalThreshold;
    std::size_t maxStackUsage;
};

inline SboTraitSummary analyze_sbo_traits() {
    using namespace reaction::memory;

    return SboTraitSummary{
        .tinyAlwaysSbo = SBOTraits<TinyPod>::always_sbo,
        .tinyForceHeap = SBOTraits<TinyPod>::force_heap,
        .mediumConditionalSbo = SBOTraits<MediumPod>::conditional_sbo,
        .mediumForceHeap = SBOTraits<MediumPod>::force_heap,
        .largeForceHeap = SBOTraits<LargePod>::force_heap,
        .alwaysThreshold = SBOConfig::ALWAYS_SBO_SIZE,
        .conditionalThreshold = SBOConfig::CONDITIONAL_SBO_SIZE,
        .maxStackUsage = SBOConfig::MAX_SBO_STACK_USAGE,
    };
}

}  // namespace test_reaction

test cases:
#include <gtest/gtest.h>

#include "test_sbo_traits.hpp"

namespace test_reaction {

/**
 * Test Case: Verify SBOTraits flags and SBOConfig thresholds.
 *
 * Test Scenario:
 * - Check Tiny/Medium/Large PODs against SBOTraits compile-time booleans
 * - Ensure configuration thresholds match library defaults
 */
TEST(reaction, test_sbo_traits) {
  const auto summary = analyze_sbo_traits();

  EXPECT_TRUE(summary.tinyAlwaysSbo);
  EXPECT_FALSE(summary.tinyForceHeap);
  EXPECT_TRUE(summary.mediumConditionalSbo);
  EXPECT_FALSE(summary.mediumForceHeap);
  EXPECT_TRUE(summary.largeForceHeap);
  EXPECT_EQ(summary.alwaysThreshold, 16u);
  EXPECT_EQ(summary.conditionalThreshold, 32u);
  EXPECT_EQ(summary.maxStackUsage, 64u * 1024u);
}

}  // namespace test_reaction

