#pragma once

#include <reaction/reaction.h>
#include <reaction/expression/expression_builders.h>

namespace test_reaction {

/**
 * Struct: RawExpressionSnapshot
 *
 * Captures the values produced by raw expression builder helpers
 * (`make_binary_expr`, `make_unary_expr`) before and after updating
 * their reactive inputs.
 */
struct RawExpressionSnapshot {
    int initialSum;
    int initialNegatedSum;
    int initialChainedValue;

    int updatedSum;
    int updatedNegatedSum;
    int updatedChainedValue;
};

/**
 * Function: test_raw_expression_builders
 *
 * Demonstrates how low-level expression builder helpers
 * (`make_binary_expr`, `make_unary_expr`) can be combined with
 * `expr` to build reactive calculations without using the higher
 * level `make_binary_op` / `make_unary_op` shortcuts.
 *
 * The function:
 * - Creates three reactive integers A, B, C.
 * - Builds sum = A + B via make_binary_expr.
 * - Builds negated = -(A + B) via make_unary_expr(make_binary_expr(...)).
 * - Builds chained = -(A + B) * C via nested make_* calls.
 * - Updates A and C and records all expression values before and after.
 *
 * @param a Initial value for the first input
 * @param b Initial value for the second input
 * @param c Initial value for the chaining multiplier
 * @return RawExpressionSnapshot
 *         Snapshot of sum / negated / chained values before and after updates.
 */
inline RawExpressionSnapshot test_raw_expression_builders(int a, int b, int c) {
    using namespace reaction;

    // 1. Create reactive variables for A, B, C using reaction::var
    auto A = var(a);
    auto B = var(b);
    auto C = var(c);

    // 2. Build sum expression using reaction::make_binary_expr<reaction::AddOp>
    auto sumExpr = make_binary_expr<AddOp>(A, B);

    // 3. Build negated expression using reaction::make_unary_expr<reaction::NegOp>
    auto negatedExpr = make_unary_expr<NegOp>(sumExpr);

    // 4. Build chained expression using reaction::make_binary_expr<reaction::MulOp>
    auto chainedExpr = make_binary_expr<MulOp>(negatedExpr, C);

    // 5. Wrap each expression with reaction::expr to create reactive nodes
    auto sumNode = expr(sumExpr);
    auto negatedNode = expr(negatedExpr);
    auto chainedNode = expr(chainedExpr);

    // 6. Get initial values using get() method
    int initialSum = sumNode.get();
    int initialNegatedSum = negatedNode.get();
    int initialChainedValue = chainedNode.get();

    // 7. Update A and C using value() method
    A.value(a + 1);  // Update A to trigger recomputation
    C.value(c + 1);  // Update C to trigger recomputation

    // 8. Get updated values using get() method
    int updatedSum = sumNode.get();
    int updatedNegatedSum = negatedNode.get();
    int updatedChainedValue = chainedNode.get();

    // 9. Return RawExpressionSnapshot with all captured values
    return RawExpressionSnapshot{
        initialSum,
        initialNegatedSum,
        initialChainedValue,
        updatedSum,
        updatedNegatedSum,
        updatedChainedValue
    };
}

}  // namespace test_reaction
```

## Key Implementation Details:

1. **Reactive Variable Creation**: Used `reaction::var` to create reactive variables A, B, and C with initial values.

2. **Expression Building**: 
   - Built sum expression using `reaction::make_binary_expr<reaction::AddOp>` for A + B
   - Built negated expression using `reaction::make_unary_expr<reaction::NegOp>` on the sum expression
   - Built chained expression using `reaction::make_binary_expr<reaction::MulOp>` with negated expression and C

3. **Reactive Node Wrapping**: Used `reaction::expr` to wrap each expression into reactive nodes that can be evaluated.

4. **Value Access**: Used the `get()` method to retrieve current values from the reactive nodes.

5. **Value Updates**: Used the `value()` method to update reactive variables A and C, triggering automatic recomputation of dependent expressions.

6. **Snapshot Return**: Returned a `RawExpressionSnapshot` struct containing all initial and updated values as required.

This implementation demonstrates proper usage of the reaction library's low-level expression building capabilities while following all the specified assessment objectives.

