```cpp
#pragma once

#include <reaction/expression/atomic_operations.h>
#include <cstdint>

namespace test_reaction {

/**
 * Struct: AtomicHelperSnapshot
 *
 * Records the value of an integer after a sequence of atomic compound helper
 * operations and whether each operation reported a change.
 */
struct AtomicHelperSnapshot {
    int32_t finalValue;
    bool addReportedChange;
    bool multiplyReportedChange;
    bool andReportedChange;
    bool leftShiftReportedChange;
    bool incrementReportedChange;
};

/**
 * Helper implementation type that mimics the minimal interface required by
 * reaction::atomicCompoundAssign helpers. It stores an integer and exposes
 * an atomicOperation method that receives a lambda and tracks whether the
 * value was changed.
 */
class IntAtomicImpl {
public:
    explicit IntAtomicImpl(int32_t initial) : m_value(initial), m_lastReportedChange(false) {}

    template <typename F>
    void atomicOperation(F&& op) {
        atomicOperation(std::forward<F>(op), false);
    }

    template <typename F>
    void atomicOperation(F&& op, bool forceNotify) {
        bool changed = op(m_value);
        m_lastReportedChange = changed;
        if (forceNotify) {
            m_lastReportedChange = true;
        }
    }

    int32_t value() const {
        return m_value;
    }

    bool lastReportedChange() const {
        return m_lastReportedChange;
    }

private:
    int32_t m_value;
    bool m_lastReportedChange;
};

/**
 * Function: test_atomic_compound_helpers
 *
 * Demonstrates the low-level atomic compound helper APIs:
 * - atomicCompoundAssign
 * - atomicAddAssign
 * - atomicMultiplyAssign
 * - atomicBitwiseAndAssign
 * - atomicLeftShiftAssign
 * - atomicIncrement
 *
 * These helpers operate on a simple IntAtomicImpl type instead of a full
 * React wrapper, making it easy to observe value and change reporting.
 *
 * @param initial Initial integer value
 * @return AtomicHelperSnapshot
 *         Snapshot containing the final value and which operations reported
 *         that a change occurred.
 */
inline AtomicHelperSnapshot test_atomic_compound_helpers(int32_t initial) {
    // Create IntAtomicImpl instance with initial value
    IntAtomicImpl impl(initial);

    // Apply atomic compound assignment operations and capture change reports
    bool addReportedChange = reaction::atomicAddAssign(impl, 5);
    bool multiplyReportedChange = reaction::atomicMultiplyAssign(impl, 2);
    bool andReportedChange = reaction::atomicBitwiseAndAssign(impl, 0xF);
    bool leftShiftReportedChange = reaction::atomicLeftShiftAssign(impl, 3);
    bool incrementReportedChange = reaction::atomicIncrement(impl);

    // Get final value
    int32_t finalValue = impl.value();

    // Return atomic helper snapshot
    return AtomicHelperSnapshot{
        .finalValue = finalValue,
        .addReportedChange = addReportedChange,
        .multiplyReportedChange = multiplyReportedChange,
        .andReportedChange = andReportedChange,
        .leftShiftReportedChange = leftShiftReportedChange,
        .incrementReportedChange = incrementReportedChange
    };
}

}  // namespace test_reaction
```

## Key Implementation Details:

1. **IntAtomicImpl Constructor**: Initializes the value and sets the last reported change flag to false.

2. **atomicOperation Overloads**: 
   - First overload calls the second with `forceNotify = false`
   - Second overload applies the lambda to the value and sets the change flag based on the lambda result, overriding with `forceNotify` if true

3. **Value Access**: `value()` returns the current integer value, `lastReportedChange()` returns the change status

4. **Operation Sequence**: Applies all specified compound assignments in order, capturing the change report from each operation

5. **Final State Capture**: Gets the final value and compiles all change reports into the return snapshot

This implementation follows the exact sequence and requirements specified in the assessment objectives, using the proper reaction library functions and maintaining the correct state tracking throughout the operations.

